import { treeifyError, type ZodType } from 'zod';
import { logError } from '../logging/logger';

type RuntimeEnv = Record<string, string | undefined>;

const env = (globalThis as unknown as { process: { env: RuntimeEnv } }).process.env;

export function validateEnv<T>(envSchema: ZodType<T>, scope = 'config.env'): T {
  const parsed = envSchema.safeParse(env);

  if (!parsed.success) {
    logError('Invalid environment variables', {
      scope,
      extra: {
        validation: treeifyError(parsed.error),
      },
    });

    throw new Error('common.envMissing');
  }

  return parsed.data;
}
